### Part 2: Smart Tag Suggestions

#### 2.1 Content Analysis for Suggestions
**Purpose:** Suggest tags based on note content

**Implementation:**
```typescript
// In src/utils/tagSuggestions.ts
export function suggestTags(
  noteContent: string,
  noteTitle: string,
  existingTags: string[],
  allTags: Tag[],
  maxSuggestions: number = 5
): TagSuggestion[] {
  const suggestions: TagSuggestion[] = [];

  // Algorithm 1: Keyword matching
  const keywords = extractKeywords(noteContent, noteTitle);
  const matchingTags = allTags.filter(tag =>
    keywords.some(keyword => tag.name.toLowerCase().includes(keyword.toLowerCase()))
  );

  // Algorithm 2: Similar notes (same tags)
  const similarNoteTags = findSimilarNoteTags(noteContent, allNotes, allTags);

  // Algorithm 3: Folder-based suggestions
  const folderTags = getFolderCommonTags(note.folderId, notes, allTags);

  // Combine and score
  const scored = [
    ...matchingTags.map(t => ({ tag: t.name, confidence: 0.8, reason: 'keyword match' })),
    ...similarNoteTags.map(t => ({ tag: t.name, confidence: 0.6, reason: 'similar notes' })),
    ...folderTags.map(t => ({ tag: t.name, confidence: 0.4, reason: 'common in folder' })),
  ];

  // Deduplicate, sort by confidence, exclude existing
  return scored
    .filter(s => !existingTags.includes(s.tag))
    .sort((a, b) => b.confidence - a.confidence)
    .slice(0, maxSuggestions);
}

interface TagSuggestion {
  tag: string;
  confidence: number; // 0-1
  reason: string;
}
```

#### 2.2 Suggestion UI in Editor
**Purpose:** Show suggested tags while editing

**Implementation:**
```typescript
// In src/widgets/NotesEditor.tsx
const [suggestedTags, setSuggestedTags] = useState<TagSuggestion[]>([]);

useEffect(() => {
  if (!activeNote) return;

  const suggestions = suggestTags(
    activeNote.content,
    activeNote.title,
    activeNote.tags,
    allTags
  );

  setSuggestedTags(suggestions);
}, [activeNote?.content, activeNote?.title, activeNote?.tags]);

// In JSX (below editor):
{suggestedTags.length > 0 && (
  <div className="mt-4 p-3 bg-surface-secondary-light dark:bg-surface-secondary-dark rounded-lg">
    <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mb-2">
      Suggested tags:
    </p>
    <div className="flex flex-wrap gap-2">
      {suggestedTags.map(({ tag, confidence, reason }) => (
        <button
          key={tag}
          onClick={() => addTagToNote(activeNote.id, tag)}
          className="px-2 py-1 text-xs rounded-full border hover:bg-accent-blue-light transition-colors"
          title={`${Math.round(confidence * 100)}% confidence - ${reason}`}
        >
          + {tag}
        </button>
      ))}
    </div>
  </div>
)}
```

### Part 3: Bulk Tag Operations

#### 3.1 Multi-Select Mode in Notes List
**Purpose:** Select multiple notes for bulk operations

**Implementation:**
```typescript
// In src/pages/Notes.tsx
const [selectionMode, setSelectionMode] = useState(false);
const [selectedNoteIds, setSelectedNoteIds] = useState<Set<string>>(new Set());

const toggleSelection = (noteId: string) => {
  setSelectedNoteIds(prev => {
    const next = new Set(prev);
    if (next.has(noteId)) {
      next.delete(noteId);
    } else {
      next.add(noteId);
    }
    return next;
  });
};

// In toolbar:
<button
  onClick={() => {
    setSelectionMode(!selectionMode);
    if (selectionMode) setSelectedNoteIds(new Set());
  }}
>
  {selectionMode ? 'Cancel Selection' : 'Select Notes'}
</button>

// In note list items:
{selectionMode && (
  <input
    type="checkbox"
    checked={selectedNoteIds.has(note.id)}
    onChange={() => toggleSelection(note.id)}
    className="mr-2"
  />
)}
```

#### 3.2 Bulk Actions Toolbar
**Purpose:** Add/remove tags from selected notes

**Implementation:**
```typescript
// In src/pages/Notes.tsx
const [bulkTagAction, setBulkTagAction] = useState<'add' | 'remove' | null>(null);
const [bulkTagValue, setBulkTagValue] = useState('');

const applyBulkTags = (action: 'add' | 'remove', tagName: string) => {
  selectedNoteIds.forEach(noteId => {
    if (action === 'add') {
      addTagToNote(noteId, tagName);
    } else {
      removeTagFromNote(noteId, tagName);
    }
  });

  // Clear selection after action
  setSelectedNoteIds(new Set());
  setSelectionMode(false);
};

// In toolbar (shown when notes selected):
{selectedNoteIds.size > 0 && (
  <div className="flex items-center gap-2 p-2 bg-accent-blue-light dark:bg-accent-blue-dark rounded-lg">
    <span className="text-sm">
      {selectedNoteIds.size} notes selected
    </span>
    <TagPicker
      value=""
      onChange={(tagName) => applyBulkTags('add', tagName)}
      placeholder="Add tag..."
    />
    <button
      onClick={() => setBulkTagAction('remove')}
      className="text-sm px-2 py-1 rounded hover:bg-surface-hover"
    >
      Remove tag...
    </button>
  </div>
)}
```

#### 3.3 Select All / Deselect All
**Purpose:** Quick selection controls

**Implementation:**
```typescript
const selectAll = () => {
  const allIds = filteredNotes.map(n => n.id);
  setSelectedNoteIds(new Set(allIds));
};

const deselectAll = () => {
  setSelectedNoteIds(new Set());
};

// In toolbar:
{selectionMode && (
  <>
    <button onClick={selectAll}>Select All</button>
    <button onClick={deselectAll}>Deselect All</button>
  </>
)}
```

## Files to Create

### src/utils/tagSuggestions.ts
- suggestTags() - Main suggestion algorithm
- extractKeywords() - Keyword extraction from content
- findSimilarNoteTags() - Find tags from similar notes
- getFolderCommonTags() - Find common tags in folder

## Files to Modify

### src/types/notes.ts
- Add `color?: string` to Tag interface

### src/stores/useNotesStore.ts
- Add updateTagColor() action
- Add bulkAddTag() action
- Add bulkRemoveTag() action

### src/components/TagManager.tsx
- Add color picker UI (react-colorful)
- Add preset color palette
- Add color display in tag list

### src/components/TagPicker.tsx
- Update tag display to use custom colors
- Add style prop for color rendering

### src/widgets/NotesEditor.tsx
- Add suggested tags section
- Wire up tag suggestion display
- Add click handler to apply suggestion

### src/pages/Notes.tsx
- Add selection mode state
- Add multi-select checkboxes
- Add bulk actions toolbar
- Add select all/deselect all buttons

## Implementation Approach

### Phase 1: Tag Colors
1. Install react-colorful dependency
2. Add color field to Tag interface
3. Add color picker to TagManager
4. Add preset color palette
5. Update tag displays to use colors
6. Test color persistence

### Phase 2: Smart Suggestions
1. Create tagSuggestions.ts utility
2. Implement keyword extraction
3. Implement similar notes algorithm
4. Implement folder-based suggestions
5. Add suggestion UI to editor
6. Test suggestion accuracy

### Phase 3: Bulk Operations
1. Add selection mode to Notes page
2. Add checkboxes to note list
3. Add bulk actions toolbar
4. Implement bulk add/remove tag actions
5. Add select all/deselect all
6. Test bulk operations

### Phase 4: Polish
1. Add keyboard shortcuts (Cmd/Ctrl+A for select all)
2. Add tooltip showing confidence on suggestions
3. Persist tag colors to IndexedDB
4. Add loading state for suggestions
5. Optimize performance for large note collections

## Verification

**Tag Colors:**
1. Open Tag Manager
2. Click color button on a tag
3. Select preset color or use custom picker
4. Verify color saves
5. Verify color appears on tag in notes list
6. Verify color appears in tag picker

**Smart Suggestions:**
1. Create note with content "JavaScript tutorial for beginners"
2. Verify "javascript" or "tutorial" tags suggested (if they exist)
3. Click suggested tag
4. Verify tag added to note
5. Create note in same folder as tagged notes
6. Verify folder-common tags suggested

**Bulk Operations:**
1. Click "Select Notes" button
2. Check multiple notes
3. Verify selection count displays
4. Add tag via bulk toolbar
5. Verify tag added to all selected notes
6. Remove tag via bulk toolbar
7. Verify tag removed from all selected notes

## Success Criteria
- ✅ Tag colors customizable via picker or presets
- ✅ Tag colors persist to IndexedDB
- ✅ Tag colors display in all tag views
- ✅ Smart tag suggestions based on content/folder/similar notes
- ✅ Suggestions display with confidence scores
- ✅ Click suggestion adds tag to note
- ✅ Selection mode toggleable in notes list
- ✅ Multi-select with checkboxes functional
- ✅ Bulk add/remove tags works
- ✅ Select all/deselect all functional
- ✅ TypeScript strict mode compliance
- ✅ Semantic tokens used

## Non-negotiables
- Use Tailwind semantic tokens (no hardcoded colors except tag custom colors)
- TypeScript strict mode compliance
- Tag colors stored in Tag interface, persisted to IndexedDB
- Suggestions show confidence scores (0-1)
- Bulk operations are atomic (all or nothing)
- Follow CLAUDE.md patterns

## Related Files
- `src/components/TagManager.tsx` - Tag management UI
- `src/components/TagPicker.tsx` - Tag selection component
- `src/pages/Notes.tsx` - Notes list page
- `src/stores/useNotesStore.ts` - Notes state management
- `tasks/master-implementation-status.md` - Lines 562-614 (Tag audit)

## Estimated Complexity
**Medium-High** - Three distinct features, new dependency (react-colorful), suggestion algorithms, bulk operations. Can be implemented incrementally (colors → suggestions → bulk).

