   143→  // Actions - Backlinks (Phase 4)
   144→  getBacklinks: (noteId: string) => Note[];
   145→  updateLinkedNotes: (noteId: string, content: string) => void;
   146→
   147→  // P1: Unlinked mentions - Convert text to wiki link
   148→  convertToWikiLink: (noteId: string, position: number, targetTitle: string) => void;
   149→
   150→  // Actions - Templates (Phase 4)
   151→  getNoteTemplates: () => NoteTemplate[];
   152→  createNoteFromTemplate: (templateId: string) => Note | null;
   153→
   154→  // Actions - Daily Notes
   155→  getDailyNote: (date: Date) => Note | null;
   156→  createDailyNote: (date: Date) => Note;
   157→  getOrCreateDailyNote: (date: Date) => Note;
   158→
   159→  // P2: Block-level links & hover preview helpers
   160→  getBlockContent: (noteId: string, blockId: string) => string | null;
   161→  getNotePreview: (noteId: string, blockId?: string) => import('../types/notes').NotePreview | null;
   162→}
   163→
   164→/**
   165→ * Default note values
   166→ */
   167→const createDefaultNote = (overrides?: Partial<Note>): Note => {
   168→  const now = new Date();
   169→  return {
   170→    id: uuidv4(),
   171→    folderId: null,
   172→    title: NOTE_CONSTANTS.DEFAULT_TITLE,
   173→    content: '', // Empty Lexical state
   174→    contentText: '',
   175→    tags: [],
   176→    createdAt: now,
   177→    updatedAt: now,
   178→    isPinned: false,
   179→    isArchived: false,
   180→    ...overrides,
   181→  };
   182→};
   183→
   184→/**
   185→ * Sort notes based on sort config
   186→ */
   187→const sortNotes = (notes: Note[], config: NoteSortConfig): Note[] => {
   188→  const sorted = [...notes];
   189→
   190→  sorted.sort((a, b) => {
   191→    let comparison = 0;
   192→
   193→    switch (config.field) {
   194→      case 'title':
   195→        comparison = a.title.localeCompare(b.title);
   196→        break;
   197→      case 'createdAt':
   198→        comparison = a.createdAt.getTime() - b.createdAt.getTime();
   199→        break;
   200→      case 'updatedAt':
   201→        comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   202→        break;
   203→      case 'manual':
   204→        // Manual sort - preserve order (could add sortOrder field in future)
   205→        comparison = 0;
   206→        break;
   207→    }
   208→
   209→    return config.order === 'asc' ? comparison : -comparison;
   210→  });
   211→
   212→  // Always pin pinned notes to top
   213→  return sorted.sort((a, b) => {
   214→    if (a.isPinned && !b.isPinned) return -1;
   215→    if (!a.isPinned && b.isPinned) return 1;
   216→    return 0;
   217→  });
   218→};
   219→
   220→/**
   221→ * Filter notes based on filter type
   222→ */
   223→const filterNotes = (notes: Note[], filter: NoteFilter): Note[] => {
   224→  switch (filter) {
   225→    case 'favorites':
   226→      return notes.filter((note) => note.isFavorite);
   227→    case 'pinned':
   228→      return notes.filter((note) => note.isPinned);
   229→    case 'archived':
   230→      return notes.filter((note) => note.isArchived);
   231→    case 'unarchived':
   232→      return notes.filter((note) => !note.isArchived);
   233→    case 'all':
   234→    default:
   235→      return notes;
   236→  }
   237→};
   238→
   239→/**
   240→ * Create the Notes store
   241→ */
   242→export const useNotesStore = create<NotesStore>()(
   243→  persist(
   244→    (set, get) => ({
   245→      // Initial state
   246→      notes: {},
   247→      activeNoteId: null,
   248→      sortConfig: {
   249→        field: 'updatedAt',
   250→        order: 'desc',
   251→      },
   252→      filter: 'unarchived',
   253→
   254→      // CRUD Operations
   255→      createNote: (params) => {
   256→        const newNote = createDefaultNote(params);
   257→        set((state) => ({
   258→          notes: {
   259→            ...state.notes,
   260→            [newNote.id]: newNote,
   261→          },
   262→          activeNoteId: newNote.id, // Auto-select new note
   263→        }));
   264→        log.debug('Note created', { id: newNote.id });
   265→        return newNote;
   266→      },
   267→
   268→      getNote: (id) => {
   269→        return get().notes[id];
   270→      },
   271→
   272→      updateNote: (id, updates) => {
   273→        const note = get().notes[id];
   274→        if (!note) {
   275→          log.warn('Note not found', { id });
   276→          return;
   277→        }
   278→
   279→        // Only update timestamp if content/title/tags actually changed
   280→        // Skip timestamp update for UI-only changes (like folderId without content change)
   281→        const shouldUpdateTimestamp =
   282→          updates.content !== undefined ||
   283→          updates.title !== undefined ||
   284→          updates.tags !== undefined;
   285→
   286→        set((state) => ({
   287→          notes: {
   288→            ...state.notes,
   289→            [id]: {
   290→              ...note,
   291→              ...updates,
   292→              ...(shouldUpdateTimestamp ? { updatedAt: new Date() } : {}),
   293→            },
   294→          },
   295→        }));
   296→        log.debug('Note updated', { id, timestampUpdated: shouldUpdateTimestamp });
   297→      },
   298→
   299→      deleteNote: (id) => {
   300→        // Save note for undo
   301→        const noteToDelete = get().notes[id];
   302→        if (!noteToDelete) {
   303→          log.warn('Note not found', { id });
   304→          return;
   305→        }
   306→
   307→        // Store the previous activeNoteId for undo
   308→        const wasActive = get().activeNoteId === id;
   309→
   310→        // Delete the note
   311→        set((state) => {
   312→          const { [id]: deleted, ...remainingNotes } = state.notes;
   313→          return {
   314→            notes: remainingNotes,
   315→            activeNoteId: state.activeNoteId === id ? null : state.activeNoteId,
   316→          };
   317→        });
   318→
   319→        log.debug('Note deleted', { id });
   320→
   321→        // Delete associated images from IndexedDB (async, fire-and-forget)
   322→        import('../services/indexedDB').then(({ indexedDBService }) => {
   323→          indexedDBService.deleteNoteImages(id).catch((err) => {
   324→            log.error('Failed to delete note images', { id, error: err });
   325→          });
   326→        });
   327→
   328→        // Add undo action
   329→        useUndoStore.getState().addUndoAction(
   330→          `Note "${noteToDelete.title}" deleted`,
   331→          () => {
   332→            // Restore the note
   333→            set((state) => ({
   334→              notes: {
   335→                ...state.notes,
   336→                [id]: noteToDelete,
   337→              },
   338→              activeNoteId: wasActive ? id : state.activeNoteId,
   339→            }));
   340→            log.debug('Note restored (undo)', { id });
   341→          }
   342→        );
   343→      },
   344→
   345→      duplicateNote: (id) => {
   346→        const original = get().notes[id];
   347→        if (!original) {
   348→          log.warn('Note not found', { id });
   349→          return null;
   350→        }
   351→
   352→        const duplicate = createDefaultNote({
   353→          ...original,
   354→          title: `${original.title} (Copy)`,
   355→          isPinned: false, // Don't copy pin status
   356→        });
   357→
   358→        set((state) => ({
   359→          notes: {
   360→            ...state.notes,
   361→            [duplicate.id]: duplicate,
   362→          },
   363→        }));
   364→
   365→        log.debug('Note duplicated', { original: id, duplicate: duplicate.id });
   366→        return duplicate;
   367→      },
   368→
   369→      // Bulk operations
   370→      deleteNotes: (ids) => {
   371→        set((state) => {
   372→          const remainingNotes = { ...state.notes };
   373→          ids.forEach((id) => delete remainingNotes[id]);
   374→          return {
   375→            notes: remainingNotes,
   376→            activeNoteId: ids.includes(state.activeNoteId || '')
   377→              ? null
   378→              : state.activeNoteId,
   379→          };
   380→        });
   381→        log.debug('Deleted notes', { count: ids.length });
   382→
   383→        // Delete associated images from IndexedDB (async, fire-and-forget)
   384→        import('../services/indexedDB').then(({ indexedDBService }) => {
   385→          ids.forEach((id) => {
   386→            indexedDBService.deleteNoteImages(id).catch((err) => {
   387→              log.error('Failed to delete images for note', { id, error: err });
   388→            });
   389→          });
   390→        });
   391→      },
   392→
   393→      moveNotesToFolder: (noteIds, folderId) => {
   394→        set((state) => {
   395→          const updatedNotes = { ...state.notes };
   396→          noteIds.forEach((id) => {
   397→            if (updatedNotes[id]) {
