     1→/**
     2→ * Tag Suggestions Utility
     3→ *
     4→ * Generates smart tag suggestions based on:
     5→ * - Content analysis (keyword extraction)
     6→ * - Frequency (most-used tags)
     7→ * - Co-occurrence (tags often used together)
     8→ * - Hierarchical (child tags when parent selected)
     9→ * - Recent tags (recently used)
    10→ */
    11→
    12→import type { Note, TagSuggestion } from '../types/notes';
    13→
    14→/**
    15→ * Extract keywords from content for content-based suggestions
    16→ * Simple algorithm: find common words (>3 chars) that appear in tags
    17→ */
    18→function extractKeywords(content: string, allTags: string[]): string[] {
    19→  const normalized = content.toLowerCase();
    20→  const keywords: string[] = [];
    21→
    22→  // Check if any tag (or part of hierarchical tag) appears in content
    23→  allTags.forEach(tag => {
    24→    const tagParts = tag.toLowerCase().split('/');
    25→    tagParts.forEach(part => {
    26→      if (part.length > 2 && normalized.includes(part)) {
    27→        keywords.push(tag);
    28→      }
    29→    });
    30→  });
    31→
    32→  return keywords;
    33→}
    34→
    35→/**
    36→ * Get most frequently used tags across all notes
    37→ */
    38→function getMostFrequentTags(notes: Note[], limit: number): string[] {
    39→  const tagCounts = new Map<string, number>();
    40→
    41→  notes.forEach(note => {
    42→    if (!note.isArchived) {
    43→      note.tags.forEach(tag => {
    44→        tagCounts.set(tag, (tagCounts.get(tag) || 0) + 1);
    45→      });
    46→    }
    47→  });
    48→
    49→  return Array.from(tagCounts.entries())
    50→    .sort((a, b) => b[1] - a[1])
    51→    .slice(0, limit)
    52→    .map(([tag]) => tag);
    53→}
    54→
    55→/**
    56→ * Find tags that are frequently used together with existing tags
    57→ */
    58→function getCoOccurringTags(existingTags: string[], notes: Note[]): Map<string, number> {
    59→  const coOccurrence = new Map<string, number>();
    60→
    61→  notes.forEach(note => {
    62→    if (note.isArchived) return;
    63→
    64→    // Check if note has any of the existing tags
    65→    const hasExistingTag = existingTags.some(tag => note.tags.includes(tag));
    66→    if (!hasExistingTag) return;
    67→
    68→    // Count other tags in this note
    69→    note.tags.forEach(tag => {
    70→      if (!existingTags.includes(tag)) {
    71→        coOccurrence.set(tag, (coOccurrence.get(tag) || 0) + 1);
    72→      }
    73→    });
    74→  });
    75→
    76→  return coOccurrence;
    77→}
    78→
    79→/**
    80→ * Get child tags when parent tag is selected
    81→ */
    82→function getHierarchicalSuggestions(existingTags: string[], allTags: string[]): string[] {
    83→  const suggestions: string[] = [];
    84→
    85→  existingTags.forEach(parentTag => {
    86→    const prefix = parentTag + '/';
    87→    allTags.forEach(tag => {
    88→      if (tag.startsWith(prefix) && !existingTags.includes(tag)) {
    89→        suggestions.push(tag);
    90→      }
    91→    });
    92→  });
    93→
    94→  return suggestions;
    95→}
    96→
    97→/**
    98→ * Get recently used tags from latest notes
    99→ */
   100→function getRecentTags(notes: Note[], limit: number, excludeTags: string[]): string[] {
   101→  const recentTags: string[] = [];
   102→  const tagSet = new Set<string>(excludeTags);
   103→
   104→  // Sort notes by updatedAt descending
   105→  const sortedNotes = [...notes]
   106→    .filter(note => !note.isArchived)
   107→    .sort((a, b) => b.updatedAt.getTime() - a.updatedAt.getTime());
   108→
   109→  // Collect tags from most recent notes
   110→  for (const note of sortedNotes) {
   111→    for (const tag of note.tags) {
   112→      if (!tagSet.has(tag)) {
   113→        tagSet.add(tag);
   114→        recentTags.push(tag);
   115→        if (recentTags.length >= limit) {
   116→          return recentTags;
   117→        }
   118→      }
   119→    }
   120→  }
   121→
   122→  return recentTags;
   123→}
   124→
   125→/**
   126→ * Generate tag suggestions for a note
   127→ *
   128→ * @param content - Note content (plain text)
   129→ * @param existingTags - Tags already applied to this note
   130→ * @param allNotes - All notes in the system
   131→ * @param maxSuggestions - Maximum number of suggestions to return
   132→ * @returns Sorted array of tag suggestions with scores
   133→ */
   134→export function generateTagSuggestions(
