    12→import React, { useState, useMemo } from 'react';
    13→import { X, Tag as TagIcon, ChevronRight, ChevronDown } from 'lucide-react';
    14→import { useTagCounts } from '../hooks/useTags';
    15→import { buildTagTree, type TagNode } from '../utils/tagHierarchy';
    16→
    17→interface TagFilterProps {
    18→  /** Currently active tag filters */
    19→  activeTags: string[];
    20→  /** Callback when tag filter is added */
    21→  onAddTag: (tag: string) => void;
    22→  /** Callback when tag filter is removed */
    23→  onRemoveTag: (tag: string) => void;
    24→  /** Callback to clear all filters */
    25→  onClearAll: () => void;
    26→}
    27→
    28→export function TagFilter({ activeTags, onAddTag, onRemoveTag, onClearAll }: TagFilterProps) {
    29→  const tagCounts = useTagCounts();
    30→  const [expandedTags, setExpandedTags] = useState<Set<string>>(new Set());
    31→
    32→  // Build tag tree with counts
    33→  const tagCountMap = useMemo(() => {
    34→    const map: Record<string, number> = {};
    35→    tagCounts.forEach(({ tag, count }) => {
    36→      map[tag] = count;
    37→    });
    38→    return map;
    39→  }, [tagCounts]);
    40→
    41→  const allTags = useMemo(() => tagCounts.map(tc => tc.tag), [tagCounts]);
    42→  const tagTree = useMemo(() => buildTagTree(allTags, tagCountMap), [allTags, tagCountMap]);
    43→
    44→  const toggleExpand = (tag: string) => {
    45→    setExpandedTags(prev => {
    46→      const next = new Set(prev);
    47→      if (next.has(tag)) {
    48→        next.delete(tag);
    49→      } else {
    50→        next.add(tag);
    51→      }
    52→      return next;
    53→    });
    54→  };
    55→
    56→  // Recursive function to render tag tree
    57→  const renderTagNode = (node: TagNode): React.ReactNode => {
    58→    const hasChildren = node.children.length > 0;
    59→    const isExpanded = expandedTags.has(node.name);
    60→    const isActive = activeTags.includes(node.name);
    61→
    62→    return (
    63→      <div key={node.name}>
    64→        <button
    65→          onClick={() => {
    66→            if (!hasChildren && !isActive) {
    67→              onAddTag(node.name);
    68→            }
    69→          }}
    70→          disabled={isActive}
    71→          className={`
    72→            w-full flex items-center justify-between px-2 py-1.5 text-sm rounded transition-colors text-left group
    73→            ${isActive
    74→              ? 'opacity-50 cursor-not-allowed'
    75→              : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
    76→            }
    77→          `}
    78→          style={{ paddingLeft: `${node.level * 16 + 8}px` }}
    79→        >
    80→          <div className="flex items-center gap-2 flex-1 min-w-0">
    81→            {hasChildren && (
    82→              <span
    83→                onClick={(e) => {
    84→                  e.stopPropagation();
    85→                  toggleExpand(node.name);
    86→                }}
    87→                className="flex-shrink-0 cursor-pointer"
    88→              >
    89→                {isExpanded ? (
    90→                  <ChevronDown className="w-3 h-3 text-text-light-tertiary dark:text-text-dark-tertiary" />
    91→                ) : (
    92→                  <ChevronRight className="w-3 h-3 text-text-light-tertiary dark:text-text-dark-tertiary" />
    93→                )}
    94→              </span>
    95→            )}
    96→            {!hasChildren && <span className="w-3" />}
    97→            <span className={`truncate ${isActive ? '' : 'text-text-light-primary dark:text-text-dark-primary group-hover:text-accent-purple dark:group-hover:text-accent-cyan'}`}>
    98→              {node.label}
    99→            </span>
   100→            {hasChildren && (
   101→              <span className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary">
   102→                ({node.children.length})
   103→              </span>
   104→            )}
   105→          </div>
   106→          <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary flex-shrink-0 ml-2">
   107→            {node.noteCount}
   108→          </span>
   109→        </button>
   110→
   111→        {/* Render children if expanded */}
   112→        {hasChildren && isExpanded && (
   113→          <div>
   114→            {node.children.map(child => renderTagNode(child))}
   115→          </div>
   116→        )}
   117→      </div>
   118→    );
   119→  };
   120→
   121→  return (
   122→    <div className="space-y-3">
   123→      {/* Header */}
